using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change 1: Discriminator property renamed from "Discriminator" to "$type".
            // Keep the old name so existing documents and raw SQL
            // (SELECT * FROM c WHERE c.Discriminator = 'Blog') still work.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: id value no longer synthesized as "Discriminator|Key".
            // Preserve the old "Blog|{key}" format for existing documents.
            b.Property(e => e.Id).HasConversion(
                id => "Blog|" + id,
                cosmosId => cosmosId.Substring(cosmosId.IndexOf('|') + 1));

            // Breaking change 3: HasIndex() now throws on Cosmos — removed.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

